class Solution {
    public List<Long> maximumEvenSplit(long finalSum) {
        List<Long> res = new ArrayList<>();
        if ((finalSum & 1) == 1) return res;
        long sum = 0;
        long even = 2;
        while (sum + even <= finalSum) {
            res.add(even);
            sum += even;
            even += 2;
        }
        if (sum < finalSum) {
            long last = res.remove(res.size() - 1);
            res.add(last + finalSum - sum);
        }
        return res;
    }
}
```
